var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그래서, 회식을 핑계로 훈련 보고서를 작성하지 않으셨다는 겁니까?","JPN":"それで、会食を口実に訓練報告書を作成しなかったということですか？","ENG":"So, you didn't write the training report because you had to go to the office dinner?","TWN":"所以，您把聚餐當作沒寫訓練報告書的藉口？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좀 봐줘. 모의작전도 끝났으니 모처럼 부대원들 긴장도 풀어줄 겸 잠깐 다녀온 거라고.","JPN":"勘弁しろよ。模擬作戦も終わったしさ、久々に部隊員たちの緊張をほぐしがてら行ってきたんだから。","ENG":"Cut me a break, will you? I just wanted to give the boys a break after the simulation and all.","TWN":"通融一下嘛。我只是覺得模擬戰都結束了，應該帶隊員去放鬆一下而已啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"게다가~ 어차피 보고서라고 해 봤자, 매번 똑같이 쓰던 거잖아?","JPN":"それに、報告書って言っても、どうせ毎回同じ内容ばかり書いてるんだろう？","ENG":"Besides, this report is no different from all the other ones, right?","TWN":"而且～反正也只是報告書嘛，那東西每次寫的內容不都一樣嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런 무책임한 발언은 그냥 넘길 수가 없군요.","JPN":"そんな無責任な発言は聞き捨てなりません。","ENG":"I'm afraid I cannot tolerate such irresponsible rhetoric.","TWN":"您這種推卸責任的發言我可不能當作沒聽到。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"보고서는 부대운영에 있어 그만큼 중요한 부분을 차지하기 때문에 항상 꼼꼼히 작성할 필요가 있는 겁니다.","JPN":"報告書は部隊運営において、大部分を占めている為、常にきちんと作成する必要があります。","ENG":"Reports are an essential part of maintaining a military unit. That is why it is so essential to complete them meticulously.","TWN":"報告書在部隊運轉中佔了很重要的一部分，不管什麼時候都必須要認真寫。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"부대원들은 그런 소령님의 일탈행위를 지지할지 모르겠지만, 이런 사태가 장기화된다면 군 기강에 문제가 생길 겁니다.","JPN":"部隊員たちはあなたのそのような逸脱行為を支持するのかもしれませんが､こういう状態が長引くと､軍規が乱れてしまいます｡","ENG":"Although your subordinates may support such deviance by you, Major, the prolonged continuation of this shortfall could have ramifications for the entire military's discipline.","TWN":"雖然不知道隊員是否支持少校大人的瀆職行為，但這樣下去早晚會出現紀律問題。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"계속 이렇게 핑계를 대시면 저도 특단의 조치를 취하는 수 밖에 없겠군요.","JPN":"これからもこうして言い訳をすると、僕も特段の措置を講じるしかありません。","ENG":"If you keep making excuses like this, I'll have no choice but to take extra special measures as well.","TWN":"您要是繼續像現在這樣找藉口，我就只好採取一些極端手段了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아하하, 마음대로 해. 별로 무섭게 들리진 않는걸?","JPN":"あはは、勝手にしろ。あまり怖くはないな。","ENG":"Hah hah, suit yourself. You don't really scare me, kid.","TWN":"啊哈哈，隨便你吧，聽起來一點都不可怕喔？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇습니까? 그럼 저도 부담 갖지 않고 레지날드 부사령관님께 앞으로 소령님의 외출 외박을 금지해달라고 요청 드리면 되겠군요.","JPN":"そうですか？\\nなら、僕も遠慮せずにレジナルド副司令官に今後の外出外泊を禁止してほしいと申し出ることにします。","ENG":"Is that so? In that case, I suppose you won't mind if I ask Deputy Commander Reginald to deny all your leave and pass requests from now on.","TWN":"是嗎？那我就可以大膽地請雷吉納德副司令禁止少尉外出了。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"분명 흔쾌히 승인해주실 거라고 봅니다만?","JPN":"きっと喜んで承認なさると思いますよ。","ENG":"I'm certain he'd be more than happy to oblige.","TWN":"我想他一定會非常爽快地答應吧？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"야, 너 치사하게......","JPN":"おい、ずるいぞ……","ENG":"Hey, how could you?","TWN":"這，你會不會太卑鄙了……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아~ 그러니까~ 내가 지금까지 한 말들은 전부 잠꼬대였다는 거지. 그러니 오해는 말라고.","JPN":"あぁ～だから～今まで俺が言ってたことは全部寝言だったんだ。だから誤解しないでくれよ。","ENG":"Okay, uh... I was just sleep talking this entire time, alright? So I hope there are no misunderstandings.","TWN":"啊～所以說～我剛才說的話全部都只是夢話喔，你千萬不要誤會。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"훈련 보고서라고 했지? 지금 당장 써올게.","JPN":"訓練報告書って言ったな？　今すぐ書いてくるから。","ENG":"You want a training report? I'll write you one right now.","TWN":"訓練報告書是吧？我馬上就會寫好。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"풋! 웃기네.","JPN":"ぷっ！バカバカしい。","ENG":"Pfft! That's hilarious.","TWN":"噗！笑死人了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 실비아 씨. 당신도 마찬가집니다.","JPN":"それに、シルビアさん。あなたも同じです。","ENG":"And Sylvia. I have similar comments for you.","TWN":"還有，希爾維亞小姐，妳也一樣。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"응? 난 분명 말한 대로 훈련참관 보고서 작성했잖아. 그럼 된 거 아냐?","JPN":"うん？　アタシは言われた通りに訓練参観報告書を作成したわよ。何か問題でも？","ENG":"Huh? I wrote up that training observer report like you said. Doesn't that settle it?","TWN":"嗯？我不是已經寫完訓練報告書了嘛，你還要我怎樣？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"‘훈련을 구경하러 갔다. 땡볕에 고생하는 모습이 엄청 힘들어 보였다.’ 라고 쓰는 게 무슨 제대로 된 보고서라는 겁니까?","JPN":"「訓練を見に行った。強い日差しの下で苦労する隊員たちがとても大変そうだった。」\\nと書かれたものがまともな報告書だと言えないでしょう？","ENG":"\\"I went to watch some peeps train and stuff. Those poor guys looked so tired under the blazing sun.\\" You call this a proper report?","TWN":"'去看了訓練，在烈日下辛苦的樣子看起來好累。''這也算報告書嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"왜? 이름, 날짜, 내용! 필요한 양식은 전부 다 채웠잖아. 그럼 된 거 아냐?","JPN":"どうして？　名前、日付、内容！　必要な様式に全部記入したんだからそれでいいんじゃない？","ENG":"What's wrong? It's got my name, date, and content! I filled in all the required fields. Isn't that enough?","TWN":"幹嘛？姓名，日期，內容！該有的不都有了嗎？你還要我怎樣？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};